// MetricsBuilder provides an interface for scrapers to report metrics while taking care of all the transformations
// required to produce metric representation defined in metadata and user config.
type MetricsBuilder struct {
	config                                 MetricsBuilderConfig // config of the metrics builder.
	startTime                              pcommon.Timestamp    // start time that will be applied to all recorded data points.
	metricsCapacity                        int                  // maximum observed number of metrics per resource.
	metricsBuffer                          pmetric.Metrics      // accumulates metrics data before emitting.
	buildInfo                              component.BuildInfo  // contains version information.
	metricPatroniClusterUnlocked           metricPatroniClusterUnlocked
	metricPatroniDcsLastSeen               metricPatroniDcsLastSeen
	metricPatroniFailsafeModeActive        metricPatroniFailsafeModeActive
	metricPatroniHistoryLsn                metricPatroniHistoryLsn
	metricPatroniHistoryPromotedAt         metricPatroniHistoryPromotedAt
	metricPatroniHistorySize               metricPatroniHistorySize
	metricPatroniIsPaused                  metricPatroniIsPaused
	metricPatroniPendingRestart            metricPatroniPendingRestart
	metricPatroniPostgresInArchiveRecovery metricPatroniPostgresInArchiveRecovery
	metricPatroniPostgresRunning           metricPatroniPostgresRunning
	metricPatroniPostgresServerVersion     metricPatroniPostgresServerVersion
	metricPatroniPostgresState             metricPatroniPostgresState
	metricPatroniPostgresStreaming         metricPatroniPostgresStreaming
	metricPatroniPostgresTimeline          metricPatroniPostgresTimeline
	metricPatroniPostmasterStartTime       metricPatroniPostmasterStartTime
	metricPatroniPrimary                   metricPatroniPrimary
	metricPatroniQuorumStandby             metricPatroniQuorumStandby
	metricPatroniReplica                   metricPatroniReplica
	metricPatroniReplicationLag            metricPatroniReplicationLag
	metricPatroniReplicationReceiveLag     metricPatroniReplicationReceiveLag
	metricPatroniReplicationReplayLag      metricPatroniReplicationReplayLag
	metricPatroniStandbyLeader             metricPatroniStandbyLeader
	metricPatroniSyncStandby               metricPatroniSyncStandby
	metricPatroniVersion                   metricPatroniVersion
	metricPatroniXlogLocation              metricPatroniXlogLocation
	metricPatroniXlogPaused                metricPatroniXlogPaused
	metricPatroniXlogReceivedLocation      metricPatroniXlogReceivedLocation
	metricPatroniXlogReplayedLocation      metricPatroniXlogReplayedLocation
	metricPatroniXlogReplayedTimestamp     metricPatroniXlogReplayedTimestamp
}

// MetricBuilderOption applies changes to default metrics builder.
type MetricBuilderOption interface {
	apply(*MetricsBuilder)
}

type metricBuilderOptionFunc func(mb *MetricsBuilder)

func (mbof metricBuilderOptionFunc) apply(mb *MetricsBuilder) {
	mbof(mb)
}

// WithStartTime sets startTime on the metrics builder.
func WithStartTime(startTime pcommon.Timestamp) MetricBuilderOption {
	return metricBuilderOptionFunc(func(mb *MetricsBuilder) {
		mb.startTime = startTime
	})
}
func NewMetricsBuilder(mbc MetricsBuilderConfig, settings receiver.Settings, options ...MetricBuilderOption) *MetricsBuilder {
	mb := &MetricsBuilder{
		config:                                 mbc,
		startTime:                              pcommon.NewTimestampFromTime(time.Now()),
		metricsBuffer:                          pmetric.NewMetrics(),
		buildInfo:                              settings.BuildInfo,
		metricPatroniClusterUnlocked:           newMetricPatroniClusterUnlocked(mbc.Metrics.PatroniClusterUnlocked),
		metricPatroniDcsLastSeen:               newMetricPatroniDcsLastSeen(mbc.Metrics.PatroniDcsLastSeen),
		metricPatroniFailsafeModeActive:        newMetricPatroniFailsafeModeActive(mbc.Metrics.PatroniFailsafeModeActive),
		metricPatroniHistoryLsn:                newMetricPatroniHistoryLsn(mbc.Metrics.PatroniHistoryLsn),
		metricPatroniHistoryPromotedAt:         newMetricPatroniHistoryPromotedAt(mbc.Metrics.PatroniHistoryPromotedAt),
		metricPatroniHistorySize:               newMetricPatroniHistorySize(mbc.Metrics.PatroniHistorySize),
		metricPatroniIsPaused:                  newMetricPatroniIsPaused(mbc.Metrics.PatroniIsPaused),
		metricPatroniPendingRestart:            newMetricPatroniPendingRestart(mbc.Metrics.PatroniPendingRestart),
		metricPatroniPostgresInArchiveRecovery: newMetricPatroniPostgresInArchiveRecovery(mbc.Metrics.PatroniPostgresInArchiveRecovery),
		metricPatroniPostgresRunning:           newMetricPatroniPostgresRunning(mbc.Metrics.PatroniPostgresRunning),
		metricPatroniPostgresServerVersion:     newMetricPatroniPostgresServerVersion(mbc.Metrics.PatroniPostgresServerVersion),
		metricPatroniPostgresState:             newMetricPatroniPostgresState(mbc.Metrics.PatroniPostgresState),
		metricPatroniPostgresStreaming:         newMetricPatroniPostgresStreaming(mbc.Metrics.PatroniPostgresStreaming),
		metricPatroniPostgresTimeline:          newMetricPatroniPostgresTimeline(mbc.Metrics.PatroniPostgresTimeline),
		metricPatroniPostmasterStartTime:       newMetricPatroniPostmasterStartTime(mbc.Metrics.PatroniPostmasterStartTime),
		metricPatroniPrimary:                   newMetricPatroniPrimary(mbc.Metrics.PatroniPrimary),
		metricPatroniQuorumStandby:             newMetricPatroniQuorumStandby(mbc.Metrics.PatroniQuorumStandby),
		metricPatroniReplica:                   newMetricPatroniReplica(mbc.Metrics.PatroniReplica),
		metricPatroniReplicationLag:            newMetricPatroniReplicationLag(mbc.Metrics.PatroniReplicationLag),
		metricPatroniReplicationReceiveLag:     newMetricPatroniReplicationReceiveLag(mbc.Metrics.PatroniReplicationReceiveLag),
		metricPatroniReplicationReplayLag:      newMetricPatroniReplicationReplayLag(mbc.Metrics.PatroniReplicationReplayLag),
		metricPatroniStandbyLeader:             newMetricPatroniStandbyLeader(mbc.Metrics.PatroniStandbyLeader),
		metricPatroniSyncStandby:               newMetricPatroniSyncStandby(mbc.Metrics.PatroniSyncStandby),
		metricPatroniVersion:                   newMetricPatroniVersion(mbc.Metrics.PatroniVersion),
		metricPatroniXlogLocation:              newMetricPatroniXlogLocation(mbc.Metrics.PatroniXlogLocation),
		metricPatroniXlogPaused:                newMetricPatroniXlogPaused(mbc.Metrics.PatroniXlogPaused),
		metricPatroniXlogReceivedLocation:      newMetricPatroniXlogReceivedLocation(mbc.Metrics.PatroniXlogReceivedLocation),
		metricPatroniXlogReplayedLocation:      newMetricPatroniXlogReplayedLocation(mbc.Metrics.PatroniXlogReplayedLocation),
		metricPatroniXlogReplayedTimestamp:     newMetricPatroniXlogReplayedTimestamp(mbc.Metrics.PatroniXlogReplayedTimestamp),
	}

	for _, op := range options {
		op.apply(mb)
	}
	return mb
}

// updateCapacity updates max length of metrics and resource attributes that will be used for the slice capacity.
func (mb *MetricsBuilder) updateCapacity(rm pmetric.ResourceMetrics) {
	if mb.metricsCapacity < rm.ScopeMetrics().At(0).Metrics().Len() {
		mb.metricsCapacity = rm.ScopeMetrics().At(0).Metrics().Len()
	}
}

// ResourceMetricsOption applies changes to provided resource metrics.
type ResourceMetricsOption interface {
	apply(pmetric.ResourceMetrics)
}

type resourceMetricsOptionFunc func(pmetric.ResourceMetrics)

func (rmof resourceMetricsOptionFunc) apply(rm pmetric.ResourceMetrics) {
	rmof(rm)
}

// WithResource sets the provided resource on the emitted ResourceMetrics.
// It's recommended to use ResourceBuilder to create the resource.
func WithResource(res pcommon.Resource) ResourceMetricsOption {
	return resourceMetricsOptionFunc(func(rm pmetric.ResourceMetrics) {
		res.CopyTo(rm.Resource())
	})
}

// WithStartTimeOverride overrides start time for all the resource metrics data points.
// This option should be only used if different start time has to be set on metrics coming from different resources.
func WithStartTimeOverride(start pcommon.Timestamp) ResourceMetricsOption {
	return resourceMetricsOptionFunc(func(rm pmetric.ResourceMetrics) {
		var dps pmetric.NumberDataPointSlice
		metrics := rm.ScopeMetrics().At(0).Metrics()
		for i := 0; i < metrics.Len(); i++ {
			switch metrics.At(i).Type() {
			case pmetric.MetricTypeGauge:
				dps = metrics.At(i).Gauge().DataPoints()
			case pmetric.MetricTypeSum:
				dps = metrics.At(i).Sum().DataPoints()
			}
			for j := 0; j < dps.Len(); j++ {
				dps.At(j).SetStartTimestamp(start)
			}
		}
	})
}

// EmitForResource saves all the generated metrics under a new resource and updates the internal state to be ready for
// recording another set of data points as part of another resource. This function can be helpful when one scraper
// needs to emit metrics from several resources. Otherwise calling this function is not required,
// just `Emit` function can be called instead.
// Resource attributes should be provided as ResourceMetricsOption arguments.
func (mb *MetricsBuilder) EmitForResource(options ...ResourceMetricsOption) {
	rm := pmetric.NewResourceMetrics()
	ils := rm.ScopeMetrics().AppendEmpty()
	ils.Scope().SetName(ScopeName)
	ils.Scope().SetVersion(mb.buildInfo.Version)
	ils.Metrics().EnsureCapacity(mb.metricsCapacity)
	mb.metricPatroniClusterUnlocked.emit(ils.Metrics())
	mb.metricPatroniDcsLastSeen.emit(ils.Metrics())
	mb.metricPatroniFailsafeModeActive.emit(ils.Metrics())
	mb.metricPatroniHistoryLsn.emit(ils.Metrics())
	mb.metricPatroniHistoryPromotedAt.emit(ils.Metrics())
	mb.metricPatroniHistorySize.emit(ils.Metrics())
	mb.metricPatroniIsPaused.emit(ils.Metrics())
	mb.metricPatroniPendingRestart.emit(ils.Metrics())
	mb.metricPatroniPostgresInArchiveRecovery.emit(ils.Metrics())
	mb.metricPatroniPostgresRunning.emit(ils.Metrics())
	mb.metricPatroniPostgresServerVersion.emit(ils.Metrics())
	mb.metricPatroniPostgresState.emit(ils.Metrics())
	mb.metricPatroniPostgresStreaming.emit(ils.Metrics())
	mb.metricPatroniPostgresTimeline.emit(ils.Metrics())
	mb.metricPatroniPostmasterStartTime.emit(ils.Metrics())
	mb.metricPatroniPrimary.emit(ils.Metrics())
	mb.metricPatroniQuorumStandby.emit(ils.Metrics())
	mb.metricPatroniReplica.emit(ils.Metrics())
	mb.metricPatroniReplicationLag.emit(ils.Metrics())
	mb.metricPatroniReplicationReceiveLag.emit(ils.Metrics())
	mb.metricPatroniReplicationReplayLag.emit(ils.Metrics())
	mb.metricPatroniStandbyLeader.emit(ils.Metrics())
	mb.metricPatroniSyncStandby.emit(ils.Metrics())
	mb.metricPatroniVersion.emit(ils.Metrics())
	mb.metricPatroniXlogLocation.emit(ils.Metrics())
	mb.metricPatroniXlogPaused.emit(ils.Metrics())
	mb.metricPatroniXlogReceivedLocation.emit(ils.Metrics())
	mb.metricPatroniXlogReplayedLocation.emit(ils.Metrics())
	mb.metricPatroniXlogReplayedTimestamp.emit(ils.Metrics())

	for _, op := range options {
		op.apply(rm)
	}

	if ils.Metrics().Len() > 0 {
		mb.updateCapacity(rm)
		rm.MoveTo(mb.metricsBuffer.ResourceMetrics().AppendEmpty())
	}
}

// Emit returns all the metrics accumulated by the metrics builder and updates the internal state to be ready for
// recording another set of metrics. This function will be responsible for applying all the transformations required to
// produce metric representation defined in metadata and user config, e.g. delta or cumulative.
func (mb *MetricsBuilder) Emit(options ...ResourceMetricsOption) pmetric.Metrics {
	mb.EmitForResource(options...)
	metrics := mb.metricsBuffer
	mb.metricsBuffer = pmetric.NewMetrics()
	return metrics
}

